def verificar_código(codigo):
    # Buscar 3 posibles fallas en el código
    fallas = []
    if "pandas" not in codigo:
        fallas.append("Falta la librería pandas")
    if "ccxt" not in codigo:
        fallas.append("Falta la librería ccxt")
    if "importlib.util.find_spec('pandas')" not in codigo:
        fallas.append("No se encuentra la librería pandas")

    # Si hay fallas, devolver un mensaje de error
    if len(fallas) > 0:
        return f"Error: {', '.join(fallas)}"
    else:
        return "Código verificado con éxito"

